import React from 'react';
import './Footer.css';

export default function Footer() {
  return (
    <footer className="footer-section">
      <div className="container">
        <h3 className="footer-logo">D &amp; C</h3>
        <p className="footer-thanks">Thank you for being part of our story.</p>
        <div className="footer-socials">
          <a href="#" className="social-icon" aria-label="Twitter">🕊</a>
          <a href="#" className="social-icon" aria-label="Facebook">👥</a>
          <a href="#" className="social-icon" aria-label="Instagram">📸</a>
        </div>
        <div className="footer-credits">
          <p>&copy; {new Date().getFullYear()} Dinusha &amp; Chamini. All Rights Reserved.</p>
          <p className="credits-designed">Designed for our special day.</p>
        </div>
      </div>
    </footer>
  );
}
